-- =============================================================================
-- MinervaDB GST Calculator for CPG
-- File: tests/test_gst_calculation.sql
-- Description: Unit tests for GST rate lookup and tax calculation functions
-- Brand: MinervaDB GST Calculator for CPG
-- License: MIT
--
-- Run: psql -d minervadb_gst_cpg -f tests/test_gst_calculation.sql
-- Expected: All assertions PASS (no RAISE EXCEPTION)
-- =============================================================================

SET search_path TO gst, public;

DO $$
DECLARE
    v_result     gst.tax_calculation_result;
        v_rate       RECORD;
            v_bool       BOOLEAN;
                v_pass_count INT := 0;
                    v_fail_count INT := 0;
                    BEGIN

                        RAISE NOTICE '=== MinervaDB GST Calculator — Unit Tests ===';
                            RAISE NOTICE 'Running: test_gst_calculation.sql';
                                RAISE NOTICE '';

                                    -- -----------------------------------------------------------------------
                                        -- TEST 1: GST Rate Lookup — Biscuits (HSN 1905) should return 12%
                                            -- -----------------------------------------------------------------------
                                                BEGIN
                                                        SELECT * INTO v_rate FROM gst.get_gst_rate('1905', CURRENT_DATE);
                                                                IF v_rate.igst_rate = 12 THEN
                                                                            RAISE NOTICE 'PASS [T01] HSN 1905 (Biscuits) IGST rate = 12%%';
                                                                                        v_pass_count := v_pass_count + 1;
                                                                                                ELSE
                                                                                                            RAISE WARNING 'FAIL [T01] HSN 1905 expected IGST 12%%, got %%', v_rate.igst_rate;
                                                                                                                        v_fail_count := v_fail_count + 1;
                                                                                                                                END IF;
                                                                                                                                    EXCEPTION WHEN OTHERS THEN
                                                                                                                                            RAISE WARNING 'FAIL [T01] Exception: %', SQLERRM;
                                                                                                                                                    v_fail_count := v_fail_count + 1;
                                                                                                                                                        END;
                                                                                                                                                        
                                                                                                                                                            -- -----------------------------------------------------------------------
                                                                                                                                                                -- TEST 2: GST Rate Lookup — Aerated drinks (HSN 2202) should return 28% + Cess
                                                                                                                                                                    -- -----------------------------------------------------------------------
                                                                                                                                                                        BEGIN
                                                                                                                                                                                SELECT * INTO v_rate FROM gst.get_gst_rate('2202', CURRENT_DATE);
                                                                                                                                                                                        IF v_rate.igst_rate = 28 AND v_rate.cess_rate = 12 THEN
                                                                                                                                                                                                    RAISE NOTICE 'PASS [T02] HSN 2202 (Aerated drinks) IGST=28%%, Cess=12%%';
                                                                                                                                                                                                                v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                        ELSE
                                                                                                                                                                                                                                    RAISE WARNING 'FAIL [T02] HSN 2202 expected IGST=28 Cess=12, got IGST=% Cess=%',
                                                                                                                                                                                                                                                    v_rate.igst_rate, v_rate.cess_rate;
                                                                                                                                                                                                                                                                v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                        END IF;
                                                                                                                                                                                                                                                                            EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                    RAISE WARNING 'FAIL [T02] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                            v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                END;
                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                    -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                        -- TEST 3: GST Rate Lookup — Milk (HSN 0401) should return 0%
                                                                                                                                                                                                                                                                                                            -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                BEGIN
                                                                                                                                                                                                                                                                                                                        SELECT * INTO v_rate FROM gst.get_gst_rate('0401', CURRENT_DATE);
                                                                                                                                                                                                                                                                                                                                IF v_rate.igst_rate = 0 AND v_rate.supply_category = 'NIL_RATED' THEN
                                                                                                                                                                                                                                                                                                                                            RAISE NOTICE 'PASS [T03] HSN 0401 (Milk) is NIL_RATED (0%%)';
                                                                                                                                                                                                                                                                                                                                                        v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                                                                                                                                                                ELSE
                                                                                                                                                                                                                                                                                                                                                                            RAISE WARNING 'FAIL [T03] HSN 0401 expected NIL_RATED, got %%', v_rate.supply_category;
                                                                                                                                                                                                                                                                                                                                                                                        v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                END IF;
                                                                                                                                                                                                                                                                                                                                                                                                    EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                                                                                                                                            RAISE WARNING 'FAIL [T03] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                                                                                                                                                    v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                        END;
                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                            -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                -- TEST 4: Intra-state calculation (Maharashtra to Maharashtra)
                                                                                                                                                                                                                                                                                                                                                                                                                                    --         Biscuits (HSN 1905) Rs 10,000 → CGST 6% + SGST 6% = Rs 600 + 600
                                                                                                                                                                                                                                                                                                                                                                                                                                        -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                            BEGIN
                                                                                                                                                                                                                                                                                                                                                                                                                                                    v_result := gst.calculate_line_item_tax(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                p_hsn_code       => '1905',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            p_taxable_value  => 10000.00,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        p_seller_state   => 'MH',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    p_buyer_state    => 'MH',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                p_transaction_date => CURRENT_DATE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                IF v_result.is_igst = FALSE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           AND v_result.cgst_amount = 600.00
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      AND v_result.sgst_amount = 600.00
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 AND v_result.igst_amount = 0.00 THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             RAISE NOTICE 'PASS [T04] Intra-state biscuits: CGST=600, SGST=600, IGST=0';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 ELSE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             RAISE WARNING 'FAIL [T04] Expected CGST=600 SGST=600 IGST=0, got CGST=% SGST=% IGST=%',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             v_result.cgst_amount, v_result.sgst_amount, v_result.igst_amount;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 END IF;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             RAISE WARNING 'FAIL [T04] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         END;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 -- TEST 5: Inter-state calculation (Maharashtra to Karnataka)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     --         Biscuits (HSN 1905) Rs 10,000 → IGST 12% = Rs 1200
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             BEGIN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     v_result := gst.calculate_line_item_tax(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 p_hsn_code       => '1905',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             p_taxable_value  => 10000.00,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         p_seller_state   => 'MH',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     p_buyer_state    => 'KA',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 p_transaction_date => CURRENT_DATE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 IF v_result.is_igst = TRUE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            AND v_result.igst_amount = 1200.00
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       AND v_result.cgst_amount = 0.00
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  AND v_result.sgst_amount = 0.00 THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              RAISE NOTICE 'PASS [T05] Inter-state biscuits MH->KA: IGST=1200, CGST=0, SGST=0';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ELSE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              RAISE WARNING 'FAIL [T05] Expected IGST=1200 CGST=0 SGST=0, got IGST=% CGST=% SGST=%',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              v_result.igst_amount, v_result.cgst_amount, v_result.sgst_amount;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  END IF;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              RAISE WARNING 'FAIL [T05] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          END;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  -- TEST 6: NIL-rated supply (Milk HSN 0401) should have zero tax
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          BEGIN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  v_result := gst.calculate_line_item_tax(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              p_hsn_code       => '0401',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          p_taxable_value  => 5000.00,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      p_seller_state   => 'PB',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  p_buyer_state    => 'HR',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              p_transaction_date => CURRENT_DATE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              IF v_result.total_tax_amount = 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         AND v_result.supply_category = 'NIL_RATED' THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     RAISE NOTICE 'PASS [T06] Milk (HSN 0401) NIL rated: total tax = 0';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         ELSE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     RAISE WARNING 'FAIL [T06] Milk expected 0 tax, got total_tax=%', v_result.total_tax_amount;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         END IF;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     RAISE WARNING 'FAIL [T06] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 END;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         -- TEST 7: Cess calculation — Aerated drinks Rs 10,000
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             --         IGST 28% = 2800, Cess 12% = 1200, Total = 4000
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     BEGIN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             v_result := gst.calculate_line_item_tax(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         p_hsn_code       => '2202',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     p_taxable_value  => 10000.00,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 p_seller_state   => 'DL',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             p_buyer_state    => 'UP',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         p_transaction_date => CURRENT_DATE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         IF v_result.igst_amount = 2800.00
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    AND v_result.cess_amount = 1200.00
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               AND v_result.total_tax_amount = 4000.00 THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           RAISE NOTICE 'PASS [T07] Aerated drinks: IGST=2800, Cess=1200, Total=4000';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               ELSE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           RAISE WARNING 'FAIL [T07] Expected IGST=2800 Cess=1200 Total=4000, got IGST=% Cess=% Total=%',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           v_result.igst_amount, v_result.cess_amount, v_result.total_tax_amount;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               END IF;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           RAISE WARNING 'FAIL [T07] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       END;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               -- TEST 8: GSTIN Validation — valid GSTIN should return TRUE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   -- -----------------------------------------------------------------------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       BEGIN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               v_bool := gst.validate_gstin('27AABCU9603R1ZX');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       IF v_bool = TRUE THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   RAISE NOTICE 'PASS [T08] GSTIN 27AABCU9603R1ZX validated successfully';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               v_pass_count := v_pass_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       ELSE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   RAISE WARNING 'FAIL [T08] Valid GSTIN returned FALSE';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       END IF;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           EXCEPTION WHEN OTHERS THEN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   RAISE WARNING 'FAIL [T08] Exception: %', SQLERRM;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           v_fail_count := v_fail_count + 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               END;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   -- -----------------------------------------------------------------------
